const c = $input.item.json;
let score = 0;
const facteurs = [];
const jours = parseInt(c.jours_sans_contact) || 0;
if (jours > 90) { score += 40; facteurs.push(`Aucun contact depuis ${jours} jours`); }
else if (jours > 60) { score += 25; facteurs.push(`Contact espacé (${jours} jours)`); }
else if (jours > 30) { score += 10; facteurs.push(`${jours} jours sans rendez-vous`); }
const fr = parseInt(c.factures_retard) || 0;
if (fr > 0) { score += Math.min(30, fr * 15); facteurs.push(`${fr} facture(s) en retard`); }
const rec = parseInt(c.reclamations_90j) || 0;
if (rec > 0) { score += Math.min(30, rec * 15); facteurs.push(`${rec} réclamation(s) sur 90 jours`); }
const niveau = score >= 60 ? 'eleve' : score >= 30 ? 'moyen' : 'faible';
return { json: { ...c, score_risque: score, niveau, facteurs: facteurs.join(' ; ') || 'RAS' } };

