const content = $input.item.json.message.content;
const src = $('Calculer score risque').item.json;
let ai;
try { ai = JSON.parse(content.match(/\{[\s\S]*\}/)[0]); }
catch(e) { ai = { diagnostic: 'Analyse indisponible', actions: [], message_suggere: '' }; }
return { json: { ...src, diagnostic: ai.diagnostic, actions: (ai.actions || []).join(' | '), message_suggere: ai.message_suggere } };
